VALUES
  ('judicial-de09bf8b-moex-00219', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-359207d9', 'sub-judicial-de09bf8b-07', NULL, 'single_choice', '「有一座龐大的旅館，設備陳舊，管理鬆懈，營業額一落千丈。旅館的所有人聘請一 位專家來從事革新和整頓。三個月後，專家對旅館的現況有了透徹的了解，提出一 份詳細的計畫，主張把房子拆掉重新建造大樓，現有工作人員一律遣散，重新招考 訓練。旅館所有人無法接受這樣的計畫，聘請另一位專家來擔任經理。這位專家在 視察旅館的業務之後，下令換裝所有房間的自來水龍頭。新的龍頭，式樣美觀，操 作方便，絕不漏水，旅客在半夜再也聽不到滴漏之聲，可以安享一夜好睡了。就這 樣，新任經理從小處著手，積小為大，終於使旅館的作風煥然一新。旅客們發現， 這家旅館的房子雖然陳舊，但是堅固；式樣雖然古老，但是引人。於是近者悅，遠 者來。」 根據上文，旅館終能近悅遠來，其主要關鍵在於管理者：', '["不愛虛名，惟儉是尚", "前事不忘，後事之師", "圖難於其易，為大於其細", "毀譽無動於衷，榮辱在所不計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00220', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-359207d9', 'sub-judicial-de09bf8b-07', NULL, 'single_choice', '「有些公司誤以為科技能取代人力經驗所累積的技能與判斷力。資深的航太工程師 因公司進行人事精簡，在勸退聲中離開崗位。但公司為了延續重要工作，又得重新 僱用這些離職的工程師。有些看似『可有可無』的中階主管去職後，公司才了解到 他們所經手的是關鍵性工作的相關知識，公司所損失的絕非那幾個正式職稱而已。」 下列選項，最符合上文旨意的是：', '["科技能創造知識價值卻無法取代勞力工作", "公司核心知識不宜因人事更迭而中斷傳承", "精簡人事成本必造成公司動盪缺乏向心力", "公司的人事規劃不可忽略中階主管的重要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00221', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-359207d9', 'sub-judicial-de09bf8b-07', NULL, 'single_choice', '「杜克大學的麥克•沙舍夫斯基是非常成功的大學籃球隊教練，他對這種評論曾有明 智的評語。有位廣播節目評論員批評他在某場比賽的戰術指導，《華爾街日報》的記 者問他對此有何反應，他回答：『大家都可以發表意見，但不是每個人都具備形成有 價值意見所須掌握的資訊。我寧可聽我信任的人的意見，不聽脫口秀節目或報導。』」 上文中的「這種評論」是指：', '["缺乏專業的評論", "球壇權威的評論", "報紙刊載的評論", "吝於讚美的評論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00222', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-359207d9', 'sub-judicial-de09bf8b-07', NULL, 'single_choice', '「很久以前，人類都還光著腳走路。一位國王到某個偏遠的鄉間旅遊，由於路面崎嶇 不平，有很多碎石頭，刺得他的腳板又痛又麻。回到王宮後，他下令要將國內所有 道路都鋪上一層牛皮。這樣做，不只是為自己，還可造福他的人民，讓大家走路時 不再受刺痛之苦。但即使殺光國內所有的牛，也湊不到足夠的皮革，而所花費的金 錢、動用的人力，更不知有多少。這個辦法很愚蠢而且根本做不到，但因為是國王 的命令，大家也只能搖頭嘆息。一位聰明的僕人大膽向國王提出建言：『國王啊！為 什麼您要勞師動眾，犧牲那麼多頭牛，花費那麼多金錢呢？您何不只用兩小片牛皮 包住您的腳呢？』國王聽了很驚訝，當下領悟，於是立刻收回成命，改採這個建議。 據說，這就是『皮鞋』的由來。」 上文故事寓意，與下列何者最為相近？', '["這個世界只有想不到的，沒有做不到的", "想改變世界，很難；要改變自己，則較為容易", "得到一件東西需要智慧，放棄一樣東西則需要勇氣", "當命運交給你一顆酸檸檬，你要想辦法把它做成一杯可口的檸檬汁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00223', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-359207d9', 'sub-judicial-de09bf8b-07', NULL, 'single_choice', '「我在臺灣各地賞鳥的旅行見聞中發現，除了年輕學生外，大部分的賞鳥人口係生活 於都市中年以上的男女，他們多半已有家庭，趁休閒假日到野外旅行賞鳥。他們並 不完全是美國鳥類學家法蘭克•查普曼所形容的：『每一個人的心中，都隱藏著一隻 嚮往自由的鳥。』也不一定是如鳥類學者形容的，受到『火種』（啟發之意）的引燃。 他們更不具有中國固有傳統，老莊哲學裡天人合一的信念，強調自然與人是一體的。 他們也沒有明顯、強烈的『環境意識』烙印在心上。他們會感受到生態環境遭到污 染、破壞，來自於經由賞鳥，發現鳥被捕殺，數量銳減與棲息環境縮小等因素，漸 漸地也關心起自己周遭的領域。時日一久，他們的關心層面又擴大，不再止於看得 見的鳥，正如別人接觸到其他的公害問題，已擴大憂疑到未來長遠的環境危機。」 根據上文，下列有關「臺灣都市中年以上男女」的敘述，何者正確？', '["從事賞鳥活動，是渴望得到心靈上的自由", "從事賞鳥活動，是為了保護瀕臨絕種的鳥類", "憂慮未來的環境危機，是出於本身具備的環境意識", "關心生態環境污染，是因感受到週遭領域逐漸破壞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00224', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-359207d9', 'sub-judicial-de09bf8b-07', NULL, 'single_choice', '承上題，下列選項最符合旨意的是：', '["透過自然休閒旅遊，可以拓展生態環境保育觀念", "推廣天人合一的信念，可強化生態環境保育觀念", "欠缺生態環境保育意識，導致稀有珍貴鳥類絕種", "保護候鳥重要棲地，可提升發展生態觀光的潛力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00225', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-57eacf76', 'sub-judicial-de09bf8b-08', NULL, 'essay', '債務人甲之金錢債權人乙，聲請強制執行甲所有之 A地及 B地，經執行
法院於民國（下同）111 年 5 月 3 日實施查封後，甲之另一金錢債權人
丙於 111 年 6 月6 日亦聲請強制執行 A地。執行法院是否應為丙查封 A
地？丙就 B地之拍賣價金得否分配受償？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "4d4a6be888fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00226', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-57eacf76', 'sub-judicial-de09bf8b-08', NULL, 'essay', '買受人甲訴請出賣人乙將 A地所有權移轉登記予甲，並聲請法院宣告假
執行。甲取得假執行宣告之判決後，持以聲請強制執行，執行法院應如
何處理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "4d4a6be888fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00227', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-57eacf76', 'sub-judicial-de09bf8b-08', NULL, 'essay', '債務人甲之金錢債權人乙聲請強制執行甲所有之A地，甲之其他金錢債
權人丙及丁分別聲明參與分配。執行法院將 A 地拍賣所得價金新臺幣
（下同）300 萬元，按乙、丙、丁所申報之債權額（均為 200 萬元），各
分配 100 萬元。乙主張丙之債權為假債權，依法提起分配表異議之訴，
而獲勝訴判決確定。執行法院應如何重新分配？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "4d4a6be888fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00228', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-111-57eacf76', 'sub-judicial-de09bf8b-08', NULL, 'essay', '勞工甲因認雇主乙違法解僱，訴請確認甲、乙間僱傭關係存在，並聲請
在本案判決確定前乙應繼續僱用甲之定暫時狀態處分。法院裁定准許甲
之聲請，甲持以聲請強制執行，執行法院應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "4d4a6be888fe", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "107", "s": "0411", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
